  "Gravity": {
    "name": "Gravity",
    "parent": "Physics",
    "category": "Physics",
    "distance": 2,
    "slug": "gravity",
    "searchContent": "Gravity is an invisible pull. It is what keeps your feet on the ground and what makes apples fall from trees. Gravity is a fundamental interaction which causes mutual attraction between all things with mass or energy. It is what keeps the Earth in orbit around the Sun.",
    "content": {
      "Beginner": "<p>Gravity is an invisible pull. It is what keeps your feet on the ground and what makes apples fall from trees.</p>\n",
      "Intermediate": "<p>Gravity is a fundamental interaction which causes mutual attraction between all things with mass or energy. It is what keeps the Earth in orbit around the Sun.</p>\n",
      "Advanced": "<p>Gravity is most accurately described by the general theory of relativity, which describes gravity not as a force, but as a consequence of masses moving along geodesic lines in a curved spacetime.</p>\n"
    }
  },
